const items = $input.all();

return items.map(item => {
  const data = item.json.body || item.json;
  const nome = data.customer_name || 'Cliente';
  const servico = data.service || 'Serviço';
  const dataAgendamento = data.appointment_date || '';
  const horario = data.start_time || '';
  const telefone = data.customer_phone || '';
  const companyName = data.company_name || 'nosso estabelecimento';

  let phoneFormatted = telefone.replace(/\D/g, '');
  if (!phoneFormatted.startsWith('55')) {
    phoneFormatted = '55' + phoneFormatted;
  }

  const mensagem = `📋 *Confirmação de Agendamento*\n\nOlá, ${nome}!\n\nConfirmamos seu agendamento em ${companyName}:\n\n🔹 *Serviço:* ${servico}\n📅 *Data:* ${dataAgendamento}\n⏰ *Horário:* ${horario}\n\nEstamos te esperando! Caso precise alterar, é só nos avisar.\n\nAté lá! 😊`;

  return {
    json: {
      phone: phoneFormatted,
      message: mensagem,
      ...data
    }
  };
});
